                let current_len = result.len();
                if current_len == 0 {
                    continue;
                }
                let mut new_part = result.clone();
                result.append(&mut new_part);
            },
            '%' => {
                result.reverse();
            },
            _ => {
                if c.is_ascii_lowercase() {
                    result.push(c);
                }
            }
        }
        // Early exit if result is already longer than k to save computation
        if result.len() > k {
            break;
        }
    }

    if k < result.len() {
        result[k].to_string()
    } else {
        ".".to_string()
    }
}
